                    }
                }
            }
            teleportList[i][j] = list;
        }
    }
    const dist = new Array(m);
    for (let i = 0; i < m; i++) {
        dist[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dist[i][j] = new Array(k + 1).fill(Infinity);
        }
    }
    dist[0][0][0] = 0;
    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.heapifyUp(this.heap.length - 1);
        }
        pop() {
            if (this.heap.length === 0) return null;
            const val = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.heapifyDown(0);
            return val;
        }
        heapifyUp(index) {
            while (index > 0) {
                const parent = Math.floor((index - 1) / 2);
                if (this.heap[parent][0] <= this.heap[index][0]) break;
                [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
                index = parent;
            }
        }
        heapifyDown(index) {
            const length = this.heap.length;
            while (index < length) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < length && this.heap[left][0] < this.heap[smallest][0]) smallest = left;
                if (right < length && this.heap[right][0] < this.heap[smallest][0]) smallest = right;
                if (smallest === index) break;
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            }
        }
        get size() {
            return this.heap.length;
        }
    }
    const pq = new PriorityQueue();
    pq.push([0, 0, 0, 0]);
    while (pq.size > 0) {
        const [cost, i, j, t] = pq.pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (j + 1 < n) {
            const newCost = cost + grid[i][j + 1];
            if (newCost < dist[i][j + 1][t]) {
